Index: admin.html
===================================================================
--- admin.html	
+++ admin.html	
@@ -1,1032 +1,1135 @@
 <!DOCTYPE html>
 <html lang="zh-CN">
 <head>
 <meta charset="UTF-8" />
 <meta name="viewport" content="width=1280" />
 <title>一青友人 · 运营后台</title>
 <style>
 *{margin:0;padding:0;box-sizing:border-box;}
 html,body{font-family:-apple-system,BlinkMacSystemFont,"PingFang SC","Microsoft YaHei",sans-serif;background:#f5f6fa;color:#2d2d3a;font-size:13px;line-height:1.5;height:100vh;overflow:hidden;}
 button{border:none;outline:none;background:none;font-family:inherit;cursor:pointer;}
 input,textarea,select{border:none;outline:none;font-family:inherit;background:none;}
 a{text-decoration:none;color:inherit;}

 /* === 整体布局 === */
 .layout{display:grid;grid-template-columns:200px 1fr;height:100vh;}
 .sidebar{background:linear-gradient(180deg,#1e1a3a,#2a1f4a);color:#fff;overflow-y:auto;display:flex;flex-direction:column;}
 .sidebar .logo{padding:18px 20px;font-size:18px;font-weight:700;background:linear-gradient(135deg,#ff5a8a,#b66dff);-webkit-background-clip:text;background-clip:text;color:transparent;display:flex;align-items:center;gap:8px;}
 .sidebar .logo .ic{font-size:24px;background:none;-webkit-text-fill-color:initial;}
 .sidebar .nav{flex:1;padding:8px 0;}
 .sidebar .nav-item{padding:10px 20px;display:flex;align-items:center;gap:10px;color:rgba(255,255,255,.75);font-size:14px;cursor:pointer;border-left:3px solid transparent;}
 .sidebar .nav-item:hover{background:rgba(255,255,255,.05);}
 .sidebar .nav-item.active{background:rgba(255,90,138,.15);color:#ff5a8a;border-left-color:#ff5a8a;font-weight:600;}
 .sidebar .nav-item .ic{font-size:16px;}
 .sidebar .nav-item .bd{margin-left:auto;background:#ff3b5c;color:#fff;font-size:10px;padding:1px 6px;border-radius:8px;}
 .sidebar .footer{padding:14px 20px;font-size:11px;color:rgba(255,255,255,.4);border-top:1px solid rgba(255,255,255,.06);}

 .main{overflow:hidden;display:flex;flex-direction:column;}
 .header{height:54px;background:#fff;border-bottom:1px solid #eee;display:flex;align-items:center;padding:0 24px;justify-content:space-between;box-shadow:0 1px 4px rgba(0,0,0,.02);flex-shrink:0;}
 .header .title{font-size:17px;font-weight:700;}
 .header .right{display:flex;align-items:center;gap:14px;font-size:12px;color:#666;}
 .header .right .dot{display:inline-flex;align-items:center;gap:5px;}
 .header .right .dot::before{content:"";width:7px;height:7px;background:#22c55e;border-radius:50%;display:inline-block;}
 .header .right .dot.off::before{background:#ccc;}
 .content{flex:1;overflow-y:auto;padding:18px 24px;background:#f5f6fa;}

 /* === 通用控件 === */
 .btn{display:inline-flex;align-items:center;justify-content:center;height:32px;padding:0 14px;border-radius:6px;font-size:13px;font-weight:500;background:linear-gradient(135deg,#ff5a8a,#b66dff);color:#fff;transition:opacity .15s;gap:4px;}
 .btn:hover{opacity:.9;}
 .btn:disabled{opacity:.5;cursor:not-allowed;}
 .btn.ghost{background:#fff;color:#666;border:1px solid #ddd;}
 .btn.ghost:hover{border-color:#ff5a8a;color:#ff5a8a;background:#fff;}
 .btn.danger{background:#ff3b5c;}
 .btn.gold{background:linear-gradient(135deg,#ffd75e,#ff9a3c);color:#5a3a00;}
 .btn.small{height:26px;padding:0 10px;font-size:12px;}
 .btn.tiny{height:22px;padding:0 8px;font-size:11px;border-radius:4px;}

 .input{display:block;width:100%;height:32px;padding:0 10px;border:1px solid #ddd;border-radius:6px;font-size:13px;color:#2d2d3a;background:#fff;}
 .input:focus{border-color:#ff5a8a;}
 textarea.input{height:auto;padding:8px 10px;resize:vertical;font-family:inherit;line-height:1.5;}

 .card{background:#fff;border-radius:8px;box-shadow:0 1px 3px rgba(0,0,0,.04);padding:16px;}
 .card-title{font-size:14px;font-weight:700;margin-bottom:14px;display:flex;align-items:center;justify-content:space-between;}

 .tag{display:inline-flex;align-items:center;padding:2px 8px;font-size:11px;border-radius:4px;background:#f0f0f5;color:#666;}
 .tag.green{background:#dcfce7;color:#15803d;}
 .tag.red{background:#fee2e2;color:#dc2626;}
 .tag.gold{background:#fef3c7;color:#b45309;}
 .tag.purple{background:#ede9fe;color:#7c3aed;}
 .tag.pink{background:#fce7f3;color:#be185d;}

 .av{width:36px;height:36px;border-radius:50%;display:inline-flex;align-items:center;justify-content:center;color:#fff;font-weight:700;flex-shrink:0;font-size:14px;}
 .av-1{background:linear-gradient(135deg,#ff5a8a,#b66dff);}
 .av-2{background:linear-gradient(135deg,#7c5aff,#4ade80);}
 .av-3{background:linear-gradient(135deg,#ffd75e,#ff9a3c);}
 .av-4{background:linear-gradient(135deg,#ff3b5c,#ffd75e);}
 .av-5{background:linear-gradient(135deg,#4ade80,#7c5aff);}
 .av-6{background:linear-gradient(135deg,#b66dff,#ff5a8a);}
 .av-7{background:linear-gradient(135deg,#ff9a3c,#ff3b5c);}
 .av-8{background:linear-gradient(135deg,#7c5aff,#ff5a8a);}

 table{width:100%;border-collapse:collapse;font-size:13px;}
 th{text-align:left;padding:10px 12px;background:#fafafd;font-weight:600;color:#666;font-size:12px;border-bottom:1px solid #eee;}
 td{padding:10px 12px;border-bottom:1px solid #f5f5f8;vertical-align:middle;}
 tr:hover td{background:#fafafd;}

 /* === 数据看板 === */
 .kpi-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-bottom:18px;}
 .kpi-card{background:#fff;border-radius:8px;padding:16px;position:relative;overflow:hidden;}
 .kpi-card::before{content:"";position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,#ff5a8a,#b66dff);}
 .kpi-card .l{font-size:12px;color:#888;display:flex;align-items:center;gap:6px;}
 .kpi-card .v{font-size:28px;font-weight:800;color:#2d2d3a;margin-top:6px;}
 .kpi-card .d{font-size:11px;color:#888;margin-top:4px;}
 .kpi-card .d .up{color:#22c55e;}
 .kpi-card .d .down{color:#ef4444;}

 .funnel{display:flex;align-items:flex-end;gap:0;height:160px;padding:14px 0;}
 .funnel .fn{flex:1;display:flex;flex-direction:column;align-items:center;gap:6px;position:relative;}
 .funnel .fn .bar{width:80%;background:linear-gradient(180deg,#ff5a8a,#b66dff);border-radius:6px 6px 0 0;display:flex;align-items:flex-start;justify-content:center;color:#fff;font-weight:700;padding-top:8px;}
 .funnel .fn .nm{font-size:12px;color:#666;}
 .funnel .fn .v{font-size:11px;color:#888;}
 .funnel .fn::after{content:"›";position:absolute;right:-10px;top:50%;transform:translateY(-50%);font-size:24px;color:#ccc;}
 .funnel .fn:last-child::after{display:none;}

 /* === 假用户管理 === */
 .toolbar{display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;gap:10px;}
 .toolbar .left{display:flex;align-items:center;gap:8px;}
 .toolbar .left .input{width:240px;}
 .toolbar .right{display:flex;gap:8px;}

 /* === 客服工作台 === */
 .cs-layout{display:grid;grid-template-columns:280px 1fr 320px;gap:14px;height:calc(100vh - 54px - 36px);}
 .cs-col{background:#fff;border-radius:8px;display:flex;flex-direction:column;overflow:hidden;box-shadow:0 1px 3px rgba(0,0,0,.04);}
 .cs-col-head{padding:12px 14px;border-bottom:1px solid #eee;font-size:13px;font-weight:700;display:flex;justify-content:space-between;align-items:center;flex-shrink:0;}
 .cs-col-body{flex:1;overflow-y:auto;}

 .conv-item{padding:12px 14px;display:flex;gap:10px;cursor:pointer;border-bottom:1px solid #f5f5f8;}
 .conv-item:hover{background:#fafafd;}
 .conv-item.active{background:#fef0f5;border-left:3px solid #ff5a8a;padding-left:11px;}
 .conv-item .iv{flex:1;min-width:0;}
 .conv-item .iv .nm{display:flex;justify-content:space-between;align-items:center;}
 .conv-item .iv .nm .n{font-size:13px;font-weight:600;}
 .conv-item .iv .nm .t{font-size:10px;color:#999;}
 .conv-item .iv .ln{font-size:11px;color:#888;margin-top:3px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;}
 .conv-item .iv .as{font-size:10px;color:#7c3aed;margin-top:3px;}
 .conv-item .bd{background:#ff3b5c;color:#fff;font-size:10px;padding:1px 5px;border-radius:8px;min-width:16px;text-align:center;}

 .cs-chat{display:flex;flex-direction:column;}
 .cs-chat-head{padding:12px 14px;border-bottom:1px solid #eee;display:flex;align-items:center;gap:10px;flex-shrink:0;}
 .cs-chat-head .iv{flex:1;}
 .cs-chat-head .iv .n{font-size:14px;font-weight:700;}
 .cs-chat-head .iv .m{font-size:11px;color:#888;}
 .cs-msg-flow{flex:1;overflow-y:auto;padding:14px;display:flex;flex-direction:column;gap:10px;background:#fafafd;}
 .cs-sys{font-size:11px;color:#999;text-align:center;padding:6px;}
 .cs-bubble-row{display:flex;gap:8px;max-width:75%;align-items:flex-end;}
 .cs-bubble-row.fake{align-self:flex-end;flex-direction:row-reverse;}
 .cs-bubble-row .av{width:30px;height:30px;font-size:12px;}
 .cs-bubble{padding:8px 12px;border-radius:12px;background:#fff;font-size:13px;line-height:1.4;box-shadow:0 1px 2px rgba(0,0,0,.04);}
 .cs-bubble-row.fake .cs-bubble{background:linear-gradient(135deg,#ff5a8a,#b66dff);color:#fff;}
 .cs-bubble-row .meta{font-size:9px;color:#bbb;margin-top:3px;}
 .cs-input-bar{padding:12px 14px;border-top:1px solid #eee;background:#fff;flex-shrink:0;}
 .cs-input-row{display:flex;gap:8px;}
 .cs-input-row textarea{flex:1;border:1px solid #ddd;border-radius:6px;padding:8px 10px;font-size:13px;height:60px;resize:none;font-family:inherit;}
 .cs-input-row textarea:focus{border-color:#ff5a8a;}
 .cs-quick-row{display:flex;gap:6px;flex-wrap:wrap;margin-top:8px;}
 .cs-quick-row .q{padding:3px 10px;background:#f5f5f8;border-radius:12px;font-size:11px;color:#666;cursor:pointer;}
 .cs-quick-row .q:hover{background:#fef0f5;color:#ff5a8a;}

 .cs-side-section{padding:12px 14px;border-bottom:1px solid #eee;}
 .cs-side-section h4{font-size:12px;color:#888;font-weight:600;margin-bottom:8px;display:flex;align-items:center;justify-content:space-between;}
 .cs-profile{display:flex;align-items:center;gap:10px;margin-bottom:10px;}
 .cs-profile .iv{flex:1;}
 .cs-profile .iv .n{font-size:14px;font-weight:700;}
 .cs-profile .iv .m{font-size:11px;color:#888;}
 .profile-stats{display:grid;grid-template-columns:1fr 1fr;gap:6px;font-size:11px;}
 .profile-stats .ps{background:#fafafd;padding:6px 8px;border-radius:6px;}
 .profile-stats .ps .l{color:#888;}
 .profile-stats .ps .v{font-weight:700;color:#2d2d3a;margin-top:2px;}

 .ai-suggest{background:linear-gradient(135deg,rgba(255,215,94,.15),rgba(255,154,60,.05));border:1px solid rgba(255,154,60,.3);border-radius:8px;padding:10px;font-size:12px;}
 .ai-suggest .hd{font-size:11px;color:#ff9a3c;font-weight:700;margin-bottom:6px;display:flex;align-items:center;gap:4px;}
 .ai-suggest .tx{font-size:13px;color:#2d2d3a;margin:6px 0;min-height:36px;line-height:1.5;}
 .ai-suggest .act{display:flex;gap:6px;}

 /* === 推送规则 === */
 .slot-row{display:grid;grid-template-columns:auto 1fr 1fr 1fr auto;gap:10px;align-items:center;padding:10px;border-radius:6px;background:#fafafd;margin-bottom:8px;}
 .slot-row label{font-size:11px;color:#888;}
 .slot-row .input{height:28px;font-size:12px;}

 .modal{position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:1000;display:flex;align-items:center;justify-content:center;}
 .modal-card{background:#fff;border-radius:8px;width:520px;max-width:90vw;max-height:90vh;overflow:hidden;display:flex;flex-direction:column;}
 .modal-head{padding:14px 18px;border-bottom:1px solid #eee;display:flex;justify-content:space-between;align-items:center;}
 .modal-head .t{font-size:15px;font-weight:700;}
 .modal-head .x{font-size:20px;color:#999;cursor:pointer;}
 .modal-body{padding:18px;overflow-y:auto;flex:1;}
 .modal-foot{padding:12px 18px;border-top:1px solid #eee;display:flex;justify-content:flex-end;gap:8px;}

 .form-row{margin-bottom:12px;}
 .form-row label{display:block;font-size:12px;color:#666;margin-bottom:4px;font-weight:500;}

 .toast{position:fixed;top:24px;right:24px;background:#1e293b;color:#fff;padding:10px 16px;border-radius:6px;font-size:13px;z-index:9999;animation:slideIn .25s;}
 @keyframes slideIn{from{transform:translateX(120%);}to{transform:translateX(0);}}

 .empty{padding:60px 20px;text-align:center;color:#bbb;font-size:13px;}
 .empty .ei{font-size:48px;opacity:.5;margin-bottom:14px;}

 .sw{width:38px;height:22px;background:#e5e5ec;border-radius:11px;position:relative;transition:background .2s;display:inline-block;cursor:pointer;vertical-align:middle;}
 .sw.on{background:#ff5a8a;}
 .sw::after{content:"";position:absolute;top:2px;left:2px;width:18px;height:18px;background:#fff;border-radius:50%;transition:transform .2s;box-shadow:0 2px 4px rgba(0,0,0,.2);}
 .sw.on::after{transform:translateX(16px);}

 .log-row{display:flex;gap:10px;padding:8px 0;border-bottom:1px solid #f5f5f8;font-size:12px;align-items:center;}
 .log-row .t{color:#888;font-family:monospace;}
 .log-row .av{width:24px;height:24px;font-size:10px;}
 .log-row .a{flex:1;}
 </style>
 </head>
 <body>
 <div id="app"></div>
 <script src="https://unpkg.com/vue@3.4.27/dist/vue.global.prod.js"></script>
+<script src="api.js"></script>
 <script>
 const { createApp, reactive, ref, computed, watch, onMounted, nextTick } = Vue

+/* ===================== 后端API开关 =====================
+ * true  => 假用户管理、批量生成、推送等优先走后端API
+ * false => 仅本地 localStorage Mock
+ * 调用失败时降级到本地，保证后台仍可用。
+ */
+const USE_BACKEND = true
+const API = (typeof window !== 'undefined' && window.starluckApi) ? window.starluckApi : null
+const apiOn = ()=> USE_BACKEND && API
+
 /* ===================== 共享 Store（与 app.html 同源 localStorage） ===================== */
 const DEFAULT_STORE = {
   loggedIn:false, onboarded:false,
   fakeUsers:[],
   pushRules:{enabled:true, timeSlots:[
     {start:'09:00',end:'11:00',maxPer:1},
     {start:'12:00',end:'14:00',maxPer:1},
     {start:'19:00',end:'22:30',maxPer:2},
   ], strategy:'active', cooldownMin:30},
   pushLog:[],
   csConfig:{aiKey:'', systemPrompt:'你是一个温柔、有趣、积极的年轻女性，正在和一位男性聊天交友。回复要：1) 简短自然（30字内）2) 偶尔反问引导对方说更多 3) 不主动提钱、礼物、转账 4) 不暴露你是AI。', templates:['哈哈是的呢～','你说的对','在做什么呢？','想见你了','晚点聊好吗？','谢谢你的礼物～'], autoReplyEnabled:false},
   adminAnalytics:{pushed:0,opened:0,replied:0,paidAfter:0},
   user:{id:'me',name:'我',av:1,city:'上海',vip:false,vipExpire:'',followers:128,fans:256,friends:42,likes:1280},
   diamonds:666, cash:88.50, isAuthed:false, chatFreeRemain:5,
   chats:[], transactions:[],
   invitedCount:12, invitedPaid:5, invitedReward:686.50, myRank:28, inviteCode:'YQ8888',
   settings:{invisible:false,hideLoc:false,vipOnly:true,sound:true,vibrate:true},
   firstRechargeShown:false,
 }

 const store = reactive(JSON.parse(JSON.stringify(DEFAULT_STORE)))
 try{
   const saved = JSON.parse(localStorage.getItem('yqyr_store')||'null')
   if(saved){
     // 兼容旧版数据：缺字段补默认
     for(const k of Object.keys(DEFAULT_STORE)){
       if(saved[k] === undefined) saved[k] = DEFAULT_STORE[k]
     }
     Object.assign(store, saved)
   }
 }catch(e){ console.warn('load store err', e) }

 let _saveT
 watch(store, ()=>{
   clearTimeout(_saveT)
   _saveT = setTimeout(()=>{
     try{ localStorage.setItem('yqyr_store', JSON.stringify(store)) }catch(e){}
   }, 150)
 }, {deep:true})

 window.addEventListener('storage', e=>{
   if(e.key !== 'yqyr_store' || !e.newValue) return
   try{
     const incoming = JSON.parse(e.newValue)
     for(const k of Object.keys(incoming)){
       if(typeof incoming[k]==='object' && incoming[k]!==null && !Array.isArray(incoming[k])){
         Object.assign(store[k], incoming[k])
       }else{
         store[k] = incoming[k]
       }
     }
   }catch(_){}
 })

 /* ===================== Toast ===================== */
 const toastState = ref('')
 let toastTimer
 const toast = (msg)=>{
   toastState.value = msg
   clearTimeout(toastTimer)
   toastTimer = setTimeout(()=>{ toastState.value = '' }, 2000)
 }

 /* ===================== 智谱 GLM-4-Flash 客户端 ===================== */
 const glm = {
   async chat(messages, opts={}){
     const key = opts.key || store.csConfig.aiKey
     if(!key) throw new Error('未配置 API Key')
     const res = await fetch('https://open.bigmodel.cn/api/paas/v4/chat/completions', {
       method:'POST',
       headers:{'Content-Type':'application/json','Authorization':'Bearer '+key},
       body: JSON.stringify({
         model: opts.model||'glm-4-flash',
         messages,
         temperature: opts.temperature ?? 0.85,
         max_tokens: opts.max_tokens || 200,
       })
     })
     if(!res.ok){
       const err = await res.text().catch(()=>'')
       throw new Error('GLM '+res.status+': '+err.slice(0,140))
     }
     const data = await res.json()
     return data?.choices?.[0]?.message?.content?.trim()||''
   }
 }

 /* ===================== 假用户工具 ===================== */
 const FAKE_NAME_POOL = ['小诗','糖糖','梨花','若兮','茉莉','柚柚','安琪','可可','小鹿','月亮','晓雯','子萱','婉清','雨晴','南风','沐妍','栀子','清欢','一一','阿月']
 const CITY_POOL = ['上海','北京','深圳','广州','杭州','成都','南京','武汉','重庆','西安']
 const SIGN_POOL = ['寻找一个温暖的人','生活不止眼前的苟且','喜欢摄影、咖啡和旅行','期待一场认真的恋爱','喜欢看星星和电影','愿和你共度春秋','一个人也要好好生活','努力做有趣的女生']
 const TAG_POOL = ['旅行','咖啡','摄影','美食','音乐','电影','健身','读书','宠物','瑜伽','汉服','烹饪','逛街','插画','烘焙']

 const randomFakeUser = ()=>{
   const id = 'f'+Date.now()+Math.floor(Math.random()*1000)
   const name = FAKE_NAME_POOL[Math.floor(Math.random()*FAKE_NAME_POOL.length)]
   const tags = []
   while(tags.length<3){
     const t = TAG_POOL[Math.floor(Math.random()*TAG_POOL.length)]
     if(!tags.includes(t)) tags.push(t)
   }
   return {
     id, name, av:Math.floor(Math.random()*8)+1,
     age:20+Math.floor(Math.random()*10),
     city:CITY_POOL[Math.floor(Math.random()*CITY_POOL.length)],
     dist:(0.5+Math.random()*5).toFixed(1)+'km',
     tags,
     sign:SIGN_POOL[Math.floor(Math.random()*SIGN_POOL.length)],
     online:Math.random()>0.3, vip:Math.random()>0.6,
     height:158+Math.floor(Math.random()*15), weight:42+Math.floor(Math.random()*15),
     job:'设计师', edu:'本科', home:'广东深圳', love:'单身',
     persona:'温柔、爱笑、喜欢分享日常',
     csOwner:'', // 客服认领人
     createdAt:Date.now(),
   }
 }

 const findUser = id => {
-  return store.fakeUsers.find(u=>u.id===id)
+  if(id == null) return null
+  // 兼容字符串/数字 id（后端返回数字、前端旧mock可能是字符串）
+  return store.fakeUsers.find(u => u.id === id || String(u.id) === String(id)) || null
 }

 /* ===================== 视图状态 ===================== */
 const view = ref('dashboard')
 const ui = reactive({
   showFakeModal:false, editingFake:null,
   showBatchModal:false, batchCount:5,
   activeConvId:'',
   aiSuggest:'', aiLoading:false,
   reply:'',
 })

 /* ===================== 计算属性 ===================== */
 // 与假用户的对话（运营关心的）
 const fakeConvs = computed(()=>{
-  return store.chats.filter(c=>store.fakeUsers.find(f=>f.id===c.uid))
+  return store.chats.filter(c=>store.fakeUsers.find(f=>f.id===c.uid || String(f.id)===String(c.uid)))
 })
 const totalUnread = computed(()=>fakeConvs.value.reduce((s,c)=>s+(c.unread||0),0))

 const activeConv = computed(()=>store.chats.find(c=>c.id===ui.activeConvId))
 const activeFake = computed(()=>activeConv.value ? findUser(activeConv.value.uid) : null)

 /* ===================== 业务方法 ===================== */
 const ops = {
   addFake(data){
     const fake = data.id ? data : {...randomFakeUser(), ...data}
     if(data.id){
       const i = store.fakeUsers.findIndex(f=>f.id===data.id)
       if(i>=0) store.fakeUsers[i] = fake
     }else{
       store.fakeUsers.push(fake)
     }
+    // 同步到后端
