 .profile-cta{position:absolute;bottom:0;left:0;right:0;padding:12px 14px;background:#fff;display:flex;gap:8px;box-shadow:0 -4px 16px rgba(0,0,0,.05);padding-bottom:calc(12px + env(safe-area-inset-bottom,0));}
