 /* === 通用 Toast === */
 .toast{position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);background:rgba(0,0,0,.75);color:#fff;padding:10px 18px;border-radius:8px;font-size:13px;z-index:99999;animation:fadeIn .2s;}
 @keyframes fadeIn{from{opacity:0;}to{opacity:1;}}

 /* === 通用 Modal === */
 .modal-mask{position:absolute;inset:0;background:rgba(0,0,0,.5);z-index:1000;display:flex;align-items:center;justify-content:center;animation:fadeIn .2s;}
 .modal-mask.bottom{align-items:flex-end;}
 .modal-card{background:#fff;border-radius:18px;width:85%;max-width:320px;overflow:hidden;animation:modalIn .25s;}
 .modal-card.full{width:100%;border-radius:18px 18px 0 0;max-width:none;}
 @keyframes modalIn{from{transform:scale(.9);opacity:0;}to{transform:scale(1);opacity:1;}}

 /* 空状态 */
 .empty{padding:60px 20px;text-align:center;color:#bbb;font-size:13px;}
 .empty .ei{font-size:48px;opacity:.5;margin-bottom:14px;}

