         <div class="real-tip">⚠️ 头像需为本人真实照片</div>
       </div>
       <div class="onboard-form" v-if="step===2">
         <h2>你的性别？</h2>
         <div class="sub">性别决定推荐人群，请如实选择</div>
         <div class="gender-pick">
           <div class="g" :class="{on:data.gender==='male'}" @click="data.gender='male'">
             <div class="gi">👦</div><div class="gn">男生</div>
           </div>
           <div class="g" :class="{on:data.gender==='female'}" @click="data.gender='female'">
             <div class="gi">👧</div><div class="gn">女生</div>
           </div>
         </div>
