 const PageWithdraw = {
   components:{StatusBar,NavBar},
   setup(){
     const amt = ref('')
     const QUICKS = [100, 500, 1000, 5000, '全部']
     const method = ref('wx')
     const fee = computed(()=>{
       const a = +amt.value || 0
       return Math.max(1, a*0.006).toFixed(2)
     })
     const arrive = computed(()=>{
       const a = +amt.value || 0
       return Math.max(0, a - +fee.value).toFixed(2)
     })
     const pickQuick = (q)=>{
       if(q==='全部') amt.value = store.cash.toFixed(2)
       else amt.value = q
     }
     const submit = ()=>{
       const a = +amt.value
       if(!a){ toast('请输入提现金额'); return }
       biz.withdraw(a)
       if(a >= 10 && a <= store.cash){ back() }
     }
     return {amt,QUICKS,method,fee,arrive,store,pickQuick,submit}
   },
   template:`<div class="screen">
     <status-bar />
     <nav-bar title="提现" right="规则" />
     <div class="content">
       <div class="withdraw-top">
         <div class="lbl">可提现金额</div>
         <div class="amt">¥ {{store.cash.toFixed(2)}}</div>
         <div class="all" @click="pickQuick('全部')">全部提现 ›</div>
       </div>
