 },2500)

 /* ===================== 推送 Worker ===================== */
 // 由 admin 配置的 pushRules 驱动；按时段从 fakeUsers 池中挑人，给当前男用户发"打招呼"
 const PushWorker = {
   greetings: [
     '你好呀～看你头像感觉好亲切',
     '嗨～在干嘛呢',
     '在吗？刚刷到你～',
     '你好，能聊聊吗？',
     '哈喽～看了你的资料感觉很合得来诶',
     '突然好想找人聊聊天',
     '看你也在线，打个招呼～',
     '感觉我们好像挺投缘的',
   ],
   inTimeSlot(){
     if(!store.pushRules.enabled) return null
     const now = new Date()
     const hm = String(now.getHours()).padStart(2,'0')+':'+String(now.getMinutes()).padStart(2,'0')
     return store.pushRules.timeSlots.find(s=>hm>=s.start && hm<=s.end) || null
   },
   pickFakeUser(){
     if(!store.fakeUsers.length) return null
     // 过滤掉冷却中的
     const now = Date.now()
     const cooldown = (store.pushRules.cooldownMin||30) * 60000
     const eligible = store.fakeUsers.filter(fu=>{
       const last = store.pushLog.filter(p=>p.fakeUid===fu.id && p.toUid===store.user.id).pop()
       return !last || (now - last.ts) > cooldown
     })
     if(!eligible.length) return null
     return eligible[Math.floor(Math.random()*eligible.length)]
   },
   pushedThisSlot(slot){
     const today = new Date().toDateString()
     return store.pushLog.filter(p=>{
       const d = new Date(p.ts)
       return d.toDateString()===today && p.slot===slot.start && p.toUid===store.user.id
     }).length
   },
   trigger(){
     if(!store.loggedIn) return
     const slot = this.inTimeSlot()
     if(!slot) return
     if(this.pushedThisSlot(slot) >= slot.maxPer) return
     const fu = this.pickFakeUser()
     if(!fu) return
     const greet = this.greetings[Math.floor(Math.random()*this.greetings.length)]
     // 找/建会话
     let chat = store.chats.find(c=>c.uid===fu.id)
     if(!chat){
       chat = {id:'c'+Date.now()+Math.floor(Math.random()*999), uid:fu.id, lastMsg:'', time:'刚刚', unread:0, msgs:[
         {type:'sys', text:'TA向你发起了打招呼'}
       ]}
       store.chats.unshift(chat)
     }
     chat.msgs.push({type:'in', text:greet, time:'刚刚'})
     chat.lastMsg = greet
     chat.time = '刚刚'
     chat.unread = (chat.unread||0) + 1
     store.pushLog.push({ts:Date.now(), fakeUid:fu.id, toUid:store.user.id, slot:slot.start, opened:false, replied:false})
     store.adminAnalytics.pushed = (store.adminAnalytics.pushed||0) + 1
     // 全局 fakeUsers 池没有真实头像，注入到 MOCK_USERS 以便其它页面渲染
     if(!MOCK_USERS.find(u=>u.id===fu.id)) MOCK_USERS.push(fu)
     if(currentRoute.value !== '/messages' && currentRoute.value !== '/chat/'+chat.id){
       toast('💌 '+fu.name+' 向你打招呼')
     }
   },
   start(){
     // 1-3 分钟检查一次时段
     this._t = setInterval(()=>this.trigger(), 60000 + Math.random()*120000)
     // 启动后 8s 触发一次（演示用）
     setTimeout(()=>this.trigger(), 8000)
   }
 }
 PushWorker.start()

 // 调试入口：window.yqyr.* 方便控制台测试
 window.yqyr = { store, go, biz, uiState, toast }
