         tx.setUserId(userId);
         tx.setType("expense");
         tx.setAmount(amount);
         tx.setBizType("withdraw");
         tx.setRefId(order.getId());
         tx.setDescription("提现" + amount + "元，手续费" + fee + "元");
         tx.setBalanceAfter(balance.getCash());
